    private AuthenticationSuccessHandler successHandler() {
        return new SimpleUrlAuthenticationSuccessHandler("/") {
            @Override
            public void onAuthenticationSuccess(javax.servlet.http.HttpServletRequest request,
                                                javax.servlet.http.HttpServletResponse response,
                                                org.springframework.security.core.Authentication authentication) throws java.io.IOException, javax.servlet.ServletException {
                Saml2Authentication saml2Auth = (Saml2Authentication) authentication;
                String samlResponse = saml2Auth.getSaml2Response();
                Map<String, String> userAttributes = extractAttributesFromSamlResponse(samlResponse);
                HttpSession session = request.getSession();
                session.setAttribute("userAttributes", userAttributes);
                super.onAuthenticationSuccess(request, response, authentication);
            }
        };
    }

    private Map<String, String> extractAttributesFromSamlResponse(String samlResponse) {
        Map<String, String> attributes = new HashMap<>();
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);
            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(new java.io.ByteArrayInputStream(samlResponse.getBytes()));
            NodeList assertionNodes = document.getElementsByTagNameNS("*", "Assertion");
            if (assertionNodes.getLength() > 0) {
                Element assertion = (Element) assertionNodes.item(0);
                NodeList attributeNodes = assertion.getElementsByTagNameNS("*", "Attribute");
                for (int i = 0; i < attributeNodes.getLength(); i++) {
                    Element attribute = (Element) attributeNodes.item(i);
                    String name = attribute.getAttribute("Name");
                    String value = attribute.getElementsByTagNameNS("*", "AttributeValue").item(0).getTextContent();
                    attributes.put(name, value);
                }
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
        return attributes;
    }
